function candidate(requestHeaders, responseHeaders) {
  function readHeader(headers, name) {
    if (!headers) return undefined;
    var target = String(name).toLowerCase();

    if (typeof headers.get === "function") {
      var got = headers.get(name);
      return got == null ? undefined : String(got);
    }

    if (typeof headers.forEach === "function" && !(Array.isArray(headers))) {
      var found;
      headers.forEach(function (value, key) {
        if (String(key).toLowerCase() === target) found = value;
      });
      if (found != null) return Array.isArray(found) ? found.join(", ") : String(found);
    }

    if (Array.isArray(headers)) {
      var parts = [];
      for (var i = 0; i < headers.length; i++) {
        var pair = headers[i];
        if (pair && String(pair[0]).toLowerCase() === target && pair[1] != null) {
          parts.push(String(pair[1]));
        }
      }
      return parts.length ? parts.join(", ") : undefined;
    }

    for (var key in headers) {
      if (Object.prototype.hasOwnProperty.call(headers, key) && String(key).toLowerCase() === target) {
        var value = headers[key];
        return value == null ? undefined : Array.isArray(value) ? value.join(", ") : String(value);
      }
    }

    return undefined;
  }

  function hasNoCache(value) {
    if (value == null) return false;
    return String(value).split(",").some(function (part) {
      return part.trim().toLowerCase().split("=", 1)[0] === "no-cache";
    });
  }

  function splitEtags(value) {
    var text = String(value);
    var list = [];
    var start = 0;
    var quoted = false;
    var escaped = false;

    for (var i = 0; i < text.length; i++) {
      var ch = text.charAt(i);
      if (escaped) {
        escaped = false;
      } else if (ch === "\\" && quoted) {
        escaped = true;
      } else if (ch === "\"") {
        quoted = !quoted;
      } else if (ch === "," && !quoted) {
        list.push(text.slice(start, i).trim());
        start = i + 1;
      }
    }

    list.push(text.slice(start).trim());
    return list.filter(Boolean);
  }

  function normalizeEtag(value) {
    var tag = String(value).trim();
    if (/^W\s*\//i.test(tag)) tag = tag.replace(/^W\s*\/\s*/i, "");
    return tag;
  }

  var conditionTags = readHeader(requestHeaders, "if-none-match");
  var conditionDate = readHeader(requestHeaders, "if-modified-since");

  if (conditionTags == null && conditionDate == null) return false;
  if (hasNoCache(readHeader(requestHeaders, "cache-control"))) return false;

  if (conditionTags != null) {
    var requestedTags = splitEtags(conditionTags);
    var hasWildcard = requestedTags.some(function (tag) { return tag === "*"; });

    if (!hasWildcard) {
      var actualTag = readHeader(responseHeaders, "etag");
      if (actualTag == null) return false;

      var actual = normalizeEtag(actualTag);
      var matched = requestedTags.some(function (tag) {
        return normalizeEtag(tag) === actual;
      });
      if (!matched) return false;
    }
  }

  if (conditionDate != null) {
    var responseDate = readHeader(responseHeaders, "last-modified");
    if (responseDate == null) return false;

    var requestedTime = Date.parse(conditionDate);
    var responseTime = Date.parse(responseDate);
    if (!Number.isFinite(requestedTime) || !Number.isFinite(responseTime)) return false;
    if (responseTime > requestedTime) return false;
  }

  return true;
}
